&lt;li style=&quot;font-size: 12pt; color: rgb(0, 0, 0); font-family: helvetica, arial, sans-serif;&quot;&gt;&lt;span style=&quot;font-size: 12pt; color: rgb(0, 0, 0); font-family: helvetica, arial, sans-serif;&quot;&gt;Develop and execute sales strategies and tactics to generate pipeline, drive sales opportunities and deliver repeatable and predictable bookings&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 12pt; color: rgb(0, 0, 0); font-family: helvetica, arial, sans-serif;&quot;&gt;&lt;span style=&quot;font-size: 12pt; color: rgb(0, 0, 0); font-family: helvetica, arial, sans-serif;&quot;&gt;Provide timely and insightful input to other corporate functions&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 12pt; color: rgb(0, 0, 0); font-family: helvetica, arial, sans-serif;&quot;&gt;&lt;span style=&quot;font-size: 12pt; color: rgb(0, 0, 0); font-family: helvetica, arial, sans-serif;&quot;&gt;Create ROI and business justification reports based on a data-driven approach&lt;/span&gt;&lt;/li&gt;
