&lt;ul&gt;
&lt;li style=&quot;font-family: helvetica, arial, sans-serif; font-size: 12pt; color: rgb(0, 0, 0);&quot;&gt;&lt;span style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif; color: rgb(0, 0, 0);&quot;&gt;This role is hybrid (4 days a week in our SF Bay Area offices)&lt;/span&gt;&lt;/li&gt;
