&lt;li style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;&lt;span style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;Deep understanding of testing framework architecture (page objects, custom assertions, reporting integrations)&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;&lt;span style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;Strong experience with modern testing tools (Selenium, Playwright, Cypress etc) and API testing frameworks&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;&lt;span style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;Experience building CI/CD pipelines and working with Containers&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;&lt;span style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;Strong working knowledge of cloud platforms like AWS, GCP&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;&lt;span style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;Experience with performance testing tools and methodologies&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;&lt;span style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;Proven track record of building tools and frameworks used by engineering teams&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;&lt;span style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;Understanding of testing patterns and anti-patterns in automation&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;span style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;&lt;strong&gt;Location:&lt;/strong&gt;&lt;/span&gt;
&lt;ul&gt;
&lt;li style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;&lt;span style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;This role is hybrid (4 days a week in our Bangalore office)&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;span style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;&lt;strong&gt;Compensation &amp;amp; Benefits:&lt;/strong&gt;&lt;/span&gt;&lt;/div&gt;
