&lt;li style=&quot;font-size: 12pt; color: rgb(0, 0, 0); font-family: helvetica, arial, sans-serif;&quot;&gt;&lt;span style=&quot;font-size: 12pt; color: rgb(0, 0, 0); font-family: helvetica, arial, sans-serif;&quot;&gt;Develop and implement automated security testing procedures.&lt;/span&gt;&lt;/li&gt;
