&lt;li style=&quot;font-family: helvetica, arial, sans-serif; font-size: 12pt;&quot;&gt;&lt;span style=&quot;font-family: helvetica, arial, sans-serif; font-size: 12pt;&quot;&gt;Proactive and self-motivated.&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-family: helvetica, arial, sans-serif; font-size: 12pt;&quot;&gt;&lt;span style=&quot;font-family: helvetica, arial, sans-serif; font-size: 12pt;&quot;&gt;Highly organized and detail-oriented.&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-family: helvetica, arial, sans-serif; font-size: 12pt;&quot;&gt;&lt;span style=&quot;font-family: helvetica, arial, sans-serif; font-size: 12pt;&quot;&gt;Startup DNA + Do Whatever It Takes (DWIT)&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-family: helvetica, arial, sans-serif; font-size: 12pt;&quot;&gt;&lt;span style=&quot;font-family: helvetica, arial, sans-serif; font-size: 12pt;&quot;&gt;Data-driven mindset for assessing success and identifying opportunities for improvement.&lt;/span&gt;&lt;/li&gt;
